SELECT MIN(value) AS min_engagement
FROM public_engagement
WHERE metric_type = 'comments';

SELECT COUNT(*) AS comment_count
FROM public_comments
WHERE bill_id = 1;

SELECT metric_type, AVG(value) AS average_engagement
FROM public_engagement
GROUP BY metric_type;

SELECT user_name, comment_text
FROM public_comments
WHERE status = 'approved';
